@echo off
chcp 65001 >nul
setlocal enabledelayedexpansion

set "SCRIPT_NAME=%~nx0"
set "VERSION=2.0"
set "PYTHON_SCRIPT=ascii_art_generator.py"

echo ========================================
echo        ASCII Art Printer v%VERSION%
echo ========================================
echo.

:: 步骤1: 检查Python环境
echo [INFO] 步骤1: 检查Python环境...
where python >nul 2>&1
if %errorlevel% neq 0 (
    echo [ERROR] 未找到Python。请安装Python并确保已添加到PATH环境变量。
    exit /b 1
)
for /f "tokens=*" %%i in ('python --version 2^>^&1') do set "PYTHON_VERSION=%%i"
echo [SUCCESS] Python已找到: !PYTHON_VERSION!
echo.

:: 步骤2: 创建Python脚本
echo [INFO] 步骤2: 生成字符画脚本...
(
echo import sys
echo import traceback
echo.
echo def generate_ascii_art():
echo     try:
echo         ascii_art = r"""
echo   _____   _____   _____   _____   _____
echo  /\    \ /\    \ /\    \ /\    \ /\    \
echo /::\    /::\    /::\    /::\    /::\    \
echo \:::\  /::::\  /::::\  /::::\  /::::\  /
echo  \:::\/::::::\/::::::\/::::::\/::::::\/
echo   \::::/~~~~  ~~~~~~~  ~~~~~~~ ~~~~~~~/
echo    \::/      /::\    \ /\    \ /\    \
echo     \/____/  \:::\    /::\    /::\    \
echo               \:::\  /::::\  /::::\  /
echo                \:::\/::::::\/::::::\/
echo                 \::::/~~~~  ~~~~~~~/
echo                  \::/      /::\    \
echo                   \/____/  \:::\    \
echo                            \:::\  /
echo                             \:::\/
echo                              \:::/
echo                               \//
echo """
echo         return ascii_art
echo     except Exception as e:
echo         print(f"[PYTHON_ERROR] 生成ASCII艺术时出错: {e}")
echo         traceback.print_exc()
echo         return None
echo.
echo if __name__ == "__main__":
echo     try:
echo         art = generate_ascii_art()
echo         if art:
echo             print(art)
echo             sys.exit(0)
echo         else:
echo             sys.exit(1)
echo     except SystemExit:
echo         raise
echo     except Exception as e:
echo         print(f"[PYTHON_CRITICAL] 脚本执行失败: {e}")
echo         traceback.print_exc()
echo         sys.exit(1)
) > "%PYTHON_SCRIPT%"

if not exist "%PYTHON_SCRIPT%" (
    echo [ERROR] 无法创建Python脚本文件。
    exit /b 1
)
echo [SUCCESS] Python脚本创建完成。
echo.

:: 步骤3: 执行Python脚本
echo [INFO] 步骤3: 执行字符画生成...
python

@echo off
chcp 65001 >nul
echo ========================================
echo Windows 11 系统信息查询脚本
echo ========================================
echo.

REM 检查系统版本
ver | findstr /i "Windows 11" >nul
if %errorlevel% neq 0 (
    echo [错误] 当前系统不是Windows 11，脚本将退出。
    exit /b 1
)

echo [步骤1/4] 正在获取系统基本信息...
systeminfo | findstr /c:"OS 名称" /c:"OS 版本" /c:"系统制造商" /c:"系统型号" /c:"系统类型" /c:"系统启动时间" /c:"处理器" /c:"物理内存总量"
if %errorlevel% neq 0 (
    echo [警告] 获取系统基本信息时遇到问题。
)

echo.
echo [步骤2/4] 正在获取磁盘信息...
wmic logicaldisk get caption,size,freespace
if %errorlevel% neq 0 (
    echo [警告] 获取磁盘信息时遇到问题。
)

echo.
echo [步骤3/4] 正在获取网络适配器信息...
ipconfig | findstr /c:"IPv4" /c:"适配器"
if %errorlevel% neq 0 (
    echo [警告] 获取网络适配器信息时遇到问题。
)

echo.
